previewCss:
.darma-loader-darma-custom-004 {
  width: 40px;
  aspect-ratio: 1;
  border-radius: 50%;
  background: radial-gradient(farthest-side, #ED303C 94%, #0000), radial-gradient(farthest-side, #FF9C5B 94%, #0000), #ED303C;
  background-position: center;
  background-repeat: no-repeat;
  animation: darma-loader-darma-custom-004-l4 1.5s infinite;
}
@keyframes darma-loader-darma-custom-004-l4 {
  0% { background-size: 0 0, 0 0; }
  30%, 50% { background-size: 0 0, 120% 120%; }
  80%, 100% { background-size: 120% 120%, 120% 120%; }
}

